mapper.select:
SELECT ta.id, c.course_code as courseCode, c.course_name as courseName, c.course_type as courseType, c.credits, c.hours, t.name as teacherName, ta.max_students as maxCount, ta.semester, (SELECT COUNT(1) FROM edu_course_selection WHERE teaching_assignment_id = ta.id) as selectedCount FROM edu_teaching_assignment ta JOIN edu_course c ON ta.course_id = c.id JOIN edu_teacher t ON ta.teacher_id = t.id WHERE ta.status = 1
AND ta.semester = #{semester}
AND ta.id NOT IN ( SELECT teaching_assignment_id FROM edu_course_selection WHERE student_id = #{studentId} )

SELECT cs.id, cs.teaching_assignment_id as course_id, cs.select_time, cs.status, c.course_code, c.course_name, c.course_type, c.credits, t.name as teacher_name, ta.semester FROM edu_course_selection cs JOIN edu_teaching_assignment ta ON cs.teaching_assignment_id = ta.id JOIN edu_course c ON ta.course_id = c.id JOIN edu_teacher t ON ta.teacher_id = t.id WHERE cs.student_id = #{studentId}
AND ta.semester = #{semester}
ORDER BY cs.select_time DESC

mapper.delete:
DELETE FROM edu_course_selection
WHERE student_id = #{studentId}
    AND teaching_assignment_id = #{teachingAssignmentId}

mapper.select:
SELECT COUNT(1)
FROM edu_course_selection
WHERE student_id = #{studentId}
    AND teaching_assignment_id = #{teachingAssignmentId}

SELECT cs.id, s.student_no as studentNo, s.name as studentName, c.course_name as courseName, t.name as teacherName, ta.semester, cs.select_time as selectTime, cs.status FROM edu_course_selection cs JOIN edu_student s ON cs.student_id = s.id JOIN edu_teaching_assignment ta ON cs.teaching_assignment_id = ta.id JOIN edu_course c ON ta.course_id = c.id JOIN edu_teacher t ON ta.teacher_id = t.id
AND ta.course_id = #{courseId}
AND ta.semester = #{semester}
ORDER BY cs.select_time DESC
